import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

const BusinessStepper = () => {
  const model = appsmith.model || {};

  // Conversion explicite en Nombre pour éviter les bugs de string "1" >= 2
  const currentStep = Number(model.step) || 0; 
  const leadCount = Number(model.leadCount) || 0;
  const compteCount = Number(model.compteCount) || 0;
  const clientCount = Number(model.clientCount) || 0;

  // Configuration des étapes
  const steps = [
    {
      id: 1,
      title: 'Lead',
      subtitle: `${leadCount} Opportunité${leadCount > 1 ? 's' : ''}`,
      // Lead est actif si on a au moins une opportunité
      active: leadCount > 0 || currentStep >= 1
    },
    {
      id: 2,
      title: 'Compte',
      subtitle: `${compteCount} Démarche${compteCount > 1 ? 's' : ''}`,
      // Compte est actif SI on a une démarche OU si le statut global est explicitement >= 2
      active: (currentStep >= 2) || (compteCount > 0)
    },
    {
      id: 3,
      title: 'Client',
      subtitle: `${clientCount} Contrat${clientCount > 1 ? 's' : ''}`,
      // Idem pour client
      active: (currentStep >= 3) || (clientCount > 0)
    }
  ];

  const colors = {
    activeBg: '#4B9F7B',    
    inactiveBg: '#F3F6FC',  
    activeText: '#FFFFFF',
    inactiveTitle: '#364152',
    inactiveSub: '#6B7280'
  };

  return (
    <div style={{ 
      display: 'flex', 
      width: '100%',
      height: '100%',
      alignItems: 'center', 
      justifyContent: 'center', 
      fontFamily: 'system-ui, -apple-system, sans-serif'
    }}>
      {/* Conteneur avec GAP pour la séparation de 4px */}
      <div style={{ 
        display: 'flex', 
        width: '100%', 
        gap: '4px' // C'est ici que se fait la séparation blanche
      }}>

        {steps.map((step, index) => {
          const isActive = step.active;
          const isFirst = index === 0;
          const isLast = index === steps.length - 1;

          // Calcul des arrondis intelligents
          // Le premier est arrondi à gauche, le dernier à droite
          // Les coins "intérieurs" sont légèrement arrondis (4px) pour l'esthétique
          let borderRadius = '4px'; 
          if (isFirst) borderRadius = '12px 4px 4px 12px';
          if (isLast) borderRadius = '4px 12px 12px 4px';

          return (
            <div key={step.id} style={{ 
              flex: 1, 
              padding: '12px 4px',
              textAlign: 'center',
              backgroundColor: isActive ? colors.activeBg : colors.inactiveBg,
              borderRadius: borderRadius, // Application de l'arrondi spécifique
              transition: 'all 0.2s ease',
              display: 'flex',
              flexDirection: 'column',
              justifyContent: 'center'
            }}>
              <div style={{ 
                fontWeight: '700', 
                fontSize: '16px', 
                marginBottom: '2px',
                color: isActive ? colors.activeText : colors.inactiveTitle
              }}>
                {step.title}
              </div>

              <div style={{ 
                fontSize: '11px', 
                fontWeight: '500',
                color: isActive ? 'rgba(255, 255, 255, 0.9)' : colors.inactiveSub
              }}>
                {step.subtitle}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

function App() {
  return <BusinessStepper />;
}

function renderApp() {
	ReactDOM.render(<App />, document.getElementById("root"));
}

appsmith.onReady(() => renderApp());
appsmith.onModelChange((newModel) => renderApp());
